{
 "level": "B2",
 "intro": "In this topic, you will learn in detail <strong>Future Perfect Passive</strong>: how to form this form, when to use it, and how it differs from other future tenses.",
 "rules": [
 {
 "label": "Formula",
 "color": "emerald",
 "text": "<strong>Subject + will have been + V3</strong>:",
 "example": "The project will have been completed by Friday."
 },
 {
 "label": "Denial",
 "color": "rose",
 "text": "<strong>Subject + will not have been + V3</strong>:",
 "example": "The report will not have been submitted by then."
 },
 {
 "label": "Question",
 "color": "blue",
 "text": "<strong>Will + Subject + have been + V3?</strong>:",
 "example": "Will the work have been finished by Monday?"
 }
 ]
}

{
 "title": "1. Structure of the Future Perfect Passive",
 "intro": "<strong>Will have been</strong> is the same for all persons:",
 "items": [
 {
 "label": "All persons",
 "title": "will have been + V3",
 "subtitle": "I/You/He/She/It/We/They will have been invited."
 },
 {
 "label": "Singular",
 "title": "will have been + V3",
 "subtitle": "The report will have been submitted. - A report will be submitted."
 },
 {
 "label": "Plural",
 "title": "will have been + V3",
 "subtitle": "All tasks will have been completed. - All tasks will be completed."
 },
 {
 "label": "Key",
 "title": "will have been is an invariable part",
 "subtitle": "will have been always comes before V3."
 }
 ]
}

{
 "title": "2. Affirmative sentences",
 "sections": [
 {
 "label": "Structure",
 "color": "emerald",
 "description": "Word order: <strong>Subject + will have been + V3 (+ by agent)</strong>",
 "examples": [
 {
 "en": "The project will have been completed by Friday.",
 "ua": "The project will have been completed by Friday."
 },
 {
 "en": "All the documents will have been signed by tomorrow.",
 "ua": "All the documents will have been signed by tomorrow."
 },
 {
 "en": "The work will have been finished by the end of the week.",
 "ua": "The work will have been finished by the end of the week."
 },
 {
 "en": "The emails will have been sent by 6 PM.",
 "ua": "The emails will have been sent by 6 PM."
 }
 ]
 },
 {
 "label": "Until a certain point",
 "color": "sky",
 "description": "We emphasize that the action <strong>will be completed by a specific time</strong>:",
 "examples": [
 {
 "en": "By next month, the building will have been renovated.",
 "ua": "By next month, the building will have been renovated."
 },
 {
 "en": "By 2030, many changes will have been made.",
 "ua": "By 2030, many changes will have been made."
 },
 {
 "en": "By the time you arrive, dinner will have been prepared.",
 "ua": "By the time you arrive, dinner will have been prepared."
 }
 ]
 }
 ]
}

{
 "title": "3. When to use Future Perfect Passive?",
 "sections": [
 {
 "label": "Completion to a point in the future",
 "color": "emerald",
 "description": "When it is important that an action <strong>be completed by a certain time</strong>:",
 "examples": [
 {
 "en": "The contract will have been signed by Monday.",
 "ua": "The contract will have been signed by Monday."
 },
 {
 "en": "The repairs will have been done by next week.",
 "ua": "The repairs will have been done by next week."
 },
 {
 "en": "The order will have been delivered by noon.",
 "ua": "The order will have been delivered by noon."
 }
 ]
 },
 {
 "label": "Deadlines and deadlines",
 "color": "blue",
 "description": "To describe <strong>completion by deadline</strong>:",
 "examples": [
 {
 "en": "The report will have been submitted before the deadline.",
 "ua": "The report will have been submitted before the deadline."
 },
 {
 "en": "All tests will have been completed by June.",
 "ua": "All tests will have been completed by June."
 },
 {
 "en": "The budget will have been approved by the end of the quarter.",
 "ua": "The budget will have been approved by the end of the quarter."
 }
 ]
 },
 {
 "label": "Forecasts for the future",
 "color": "amber",
 "description": "For completion <strong>predictions</strong>:",
 "examples": [
 {
 "en": "By 2050, many problems will have been solved.",
 "ua": "By 2050, many problems will have been solved."
 },
 {
 "en": "The new system will have been implemented by then.",
 "ua": "The new system will have been implemented by then."
 },
 {
 "en": "A cure will have been found by the end of the decade.",
 "ua": "A cure will have been found by the end of the decade."
 }
 ]
 }
 ]
}

{
 "title": "4. Negative sentences",
 "sections": [
 {
 "label": "Structure",
 "color": "rose",
 "description": "Add <strong>not</strong> after will: <strong>Subject + will not have been + V3</strong>",
 "examples": [
 {
 "en": "The project will not have been finished by Friday.",
 "ua": "The project will not have been finished by Friday."
 },
 {
 "en": "The documents will not have been signed by then.",
 "ua": "The documents will not have been signed by then."
 },
 {
 "en": "The report will not have been submitted before the deadline.",
 "ua": "The report will not have been submitted before the deadline."
 },
 {
 "en": "All tasks will not have been completed by Monday.",
 "ua": "All tasks will not have been completed by Monday."
 }
 ]
 },
 {
 "label": "Abbreviated form",
 "color": "amber",
 "description": "Colloquially: <strong>won't have been</strong>",
 "examples": [
 {
 "en": "The work won't have been finished by tomorrow.",
 "ua": "The work won't have been finished by tomorrow."
 },
 {
 "en": "The email won't have been sent by 5 PM.",
 "ua": "The email won't have been sent by 5 PM."
 },
 {
 "en": "The decision won't have been made by then.",
 "ua": "The decision won't have been made by then."
 }
 ]
 }
 ]
}

{
 "title": "5. Interrogative sentences",
 "sections": [
 {
 "label": "Yes/No question",
 "color": "blue",
 "description": "<strong>Will + Subject + have been + V3?</strong>",
 "examples": [
 {
 "en": "Will the project have been completed by Friday?",
 "ua": "Will the project have been completed by Friday?"
 },
 {
 "en": "Will all documents have been signed by tomorrow?",
 "ua": "Will all documents have been signed by tomorrow?"
 },
 {
 "en": "Will the work have been finished by then?",
 "ua": "Will the work have been finished by then?"
 },
 {
 "en": "Will the order have been delivered by noon?",
 "ua": "Will the order have been delivered by noon?"
 }
 ]
 },
 {
 "label": "Wh question",
 "color": "sky",
 "description": "<strong>Wh-word + will + Subject + have been + V3?</strong>",
 "examples": [
 {
 "en": "What will have been done by Friday?",
 "ua": "What will have been done by Friday?"
 },
 {
 "en": "How much will have been completed by the deadline?",
 "ua": "How much will have been completed by the deadline?"
 },
 {
 "en": "When will the report have been submitted?",
 "ua": "When will the report have been submitted?"
 },
 {
 "en": "Why will the project have been delayed?",
 "ua": "Why will the project have been delayed?"
 }
 ]
 },
 {
 "label": "Short answers",
 "color": "amber",
 "description": "Answers with <strong>Yes/No + pronoun + will (not) have</strong>:",
 "examples": [
 {
 "en": "Will the email have been sent? — Yes, it will. / No, it won't.",
 "ua": "Will the email have been sent? — Yes, it will. / No, it won't."
 },
 {
 "en": "Will they have been informed? — Yes, they will. / No, they won't.",
 "ua": "Will they have been informed? — Yes, they will. / No, they won't."
 }
 ]
 }
 ]
}

{
 "title": "6. Comparison of Active vs Passive in Future Perfect",
 "intro": "How to turn an active sentence into a passive:",
 "rows": [
 {
 "en": "Active: They will have completed the project.",
 "ua": "Active: They will have completed the project.",
 "note": "→ Passive: The project will have been completed."
 },
 {
 "en": "Active: Someone will have sent the email.",
 "ua": "Active: Someone will have sent the email.",
 "note": "→ Passive: The email will have been sent."
 },
 {
 "en": "Active: The company will have hired new staff.",
 "ua": "Active: The company will have hired new staff.",
 "note": "→ Passive: New staff will have been hired."
 },
 {
 "en": "Active: We will have made a decision.",
 "ua": "Active: We will have made a decision.",
 "note": "→ Passive: A decision will have been made."
 }
 ],
 "warning": "📌 Time markers (by Friday, by then, by the end of) remain!"
}

{
 "title": "7. Comparison of all Future Passive forms",
 "intro": "The difference between the forms of the future tense in the passive:",
 "rows": [
 {
 "en": "Future Simple: The letter will be sent tomorrow.",
 "ua": "Future Simple: The letter will be sent tomorrow.",
 "note": "→ Action in the future"
 },
 {
 "en": "Future Continuous: The letter will be being written.",
 "ua": "Future Continuous: The letter will be being written.",
 "note": "→ Continuous action in the future moment (rare!)"
 },
 {
 "en": "Future Perfect: The letter will have been sent by 5 PM.",
 "ua": "Future Perfect: The letter will have been sent by 5 PM.",
 "note": "→ Will be completed by a certain time"
 }
 ],
 "warning": "📌 Future Perfect Passive emphasizes COMPLETION by a specific time!"
}

{
 "title": "8. Time markers for the Future Perfect Passive",
 "intro": "Typical words and expressions indicating the Future Perfect:",
 "items": [
 {
 "label": "To",
 "title": "Grammar focus",
 "subtitle": "The report will have been submitted by Friday."
 },
 {
 "label": "To the end",
 "title": "by the end of + period",
 "subtitle": "The project will have been completed by the end of the month."
 },
 {
 "label": "Until then",
 "title": "by then, by that time",
 "subtitle": "All tasks will have been finished by then."
 },
 {
 "label": "Up to a year",
 "title": "by 2030, by next year",
 "subtitle": "Many changes will have been made by 2030."
 }
 ]
}

{
 "title": "9. Typical mistakes",
 "items": [
 {
 "label": "Error 1",
 "color": "rose",
 "title": "Skip been.",
 "wrong": "The report will have completed.",
 "right": "✅ The report will have been completed."
 },
 {
 "label": "Error 2",
 "color": "amber",
 "title": "Confusion of been and being.",
 "wrong": "The work will have being done.",
 "right": "✅ The work will have been done."
 },
 {
 "label": "Error 3",
 "color": "sky",
 "title": "Wrong order.",
 "wrong": "The letter will been have sent.",
 "right": "✅ The letter will have been sent."
 },
 {
 "label": "Error 4",
 "color": "rose",
 "title": "Future Simple instead of Future Perfect.",
 "wrong": "The project will be finished by Friday.",
 "right": "✅ The project will have been finished by Friday."
 }
 ]
}
